-- Indexer seed data for local testing
-- Run: psql sippy_indexer < scripts/seed.sql
--
-- Creates Ponder-style tables (if not running indexer) and inserts fake data
-- so the admin dashboard has something to display.

BEGIN;

-- ============================================================
-- 1. Create tables (Ponder normally manages these)
-- ============================================================

CREATE TABLE IF NOT EXISTS account (
  address TEXT PRIMARY KEY,
  balance BIGINT NOT NULL DEFAULT 0,
  "totalSent" BIGINT NOT NULL DEFAULT 0,
  "totalReceived" BIGINT NOT NULL DEFAULT 0,
  "txCount" INTEGER NOT NULL DEFAULT 0,
  "lastActivity" INTEGER NOT NULL DEFAULT 0
);

CREATE TABLE IF NOT EXISTS transfer (
  id TEXT PRIMARY KEY,
  "from" TEXT NOT NULL,
  "to" TEXT NOT NULL,
  amount BIGINT NOT NULL,
  timestamp INTEGER NOT NULL,
  "blockNumber" INTEGER NOT NULL,
  "txHash" TEXT NOT NULL
);
CREATE INDEX IF NOT EXISTS transfer_from_idx ON transfer ("from");
CREATE INDEX IF NOT EXISTS transfer_to_idx ON transfer ("to");
CREATE INDEX IF NOT EXISTS transfer_timestamp_idx ON transfer (timestamp);

CREATE TABLE IF NOT EXISTS refuel_event (
  id TEXT PRIMARY KEY,
  "user" TEXT NOT NULL,
  amount BIGINT NOT NULL,
  timestamp INTEGER NOT NULL,
  "blockNumber" INTEGER NOT NULL,
  "txHash" TEXT NOT NULL
);
CREATE INDEX IF NOT EXISTS refuel_user_idx ON refuel_event ("user");
CREATE INDEX IF NOT EXISTS refuel_timestamp_idx ON refuel_event (timestamp);

CREATE TABLE IF NOT EXISTS gas_refuel_status (
  id TEXT PRIMARY KEY,
  "totalRefuels" INTEGER NOT NULL DEFAULT 0,
  "totalEthSpent" BIGINT NOT NULL DEFAULT 0,
  "isPaused" BOOLEAN NOT NULL DEFAULT FALSE,
  "lastRefuelAt" INTEGER NOT NULL DEFAULT 0
);

CREATE TABLE IF NOT EXISTS daily_volume (
  id TEXT PRIMARY KEY,
  date TEXT NOT NULL,
  "totalUsdcVolume" BIGINT NOT NULL DEFAULT 0,
  "transferCount" INTEGER NOT NULL DEFAULT 0,
  "gasRefuelCount" INTEGER NOT NULL DEFAULT 0,
  "gasEthSpent" BIGINT NOT NULL DEFAULT 0
);

-- Offchain schema (Drizzle-managed)
CREATE SCHEMA IF NOT EXISTS offchain;
CREATE TABLE IF NOT EXISTS offchain.sippy_wallet (
  address TEXT PRIMARY KEY,
  phone_hash TEXT,
  registered_at INTEGER NOT NULL,
  is_active BOOLEAN NOT NULL DEFAULT TRUE
);

-- ============================================================
-- 2. Clear existing seed data
-- ============================================================

DELETE FROM transfer;
DELETE FROM refuel_event;
DELETE FROM account;
DELETE FROM gas_refuel_status;
DELETE FROM daily_volume;
DELETE FROM offchain.sippy_wallet;

